# შექმენით ფუნქცია რომელსაც ერქმევა MY_info,მას უნდა გადასცე 4 არგუმენტი:სახელი,გვარი,ასაკი სიმაღლე . შენმა ფუნქციამ უნდა დააბრუნოს შენს თავზე ინფორმაცია ასეთი სახით "მე ვარ (სახელი) , (გვარი) . ჩემი წლოვანება არის (ასაკი) და ვარ (სიმაღლე) სმ"
def MY_info(name, surname, age, height):
    print("მე ვარ " + name + " , " + surname + " . ჩემი წლოვანება არის " + str(age) + " და ვარ " + str(height) + " სმ")
MY_info("გიორგი", "ბანეთიშვილი", 11 , 1.49)